from langchain.callbacks import BaseCallbackHandler

class LoopDetector(BaseCallbackHandler):
    def __init__(self):
        self.agent_calls = {}
        self.max_calls = 3

    def on_agent_action(self, action, **kwargs):
        agent_name = action.tool
        self.agent_calls[agent_name] = self.agent_calls.get(agent_name, 0) + 1
        if self.agent_calls[agent_name] > self.max_calls:
            raise ValueError(f"LOOP DETECTED: Agent {agent_name} called {self.agent_calls[agent_name]} times")

# Usage
agent_executor = AgentExecutor.from_agent_and_tools(...)
agent_executor.invoke({"input": query}, callbacks=[LoopDetector()])

def validate_handoff_state(state: dict, required_keys: list[str]):
    missing = [k for k in required_keys if k not in state]
    if missing:
        raise ValueError(f"Handoff incomplete. Missing keys: {missing}")
    return True

# LangGraph node
@node
def agent_node(state):
    result = agent_executor.invoke(state)
    new_state = {**state, **result}
    validate_handoff_state(new_state, ['task_status', 'final_answer'])
    return new_state

