from langchain.tools import BaseTool
from threading import Lock

class LockedDatabaseTool(BaseTool):
    name = 'locked_db_query'
    lock = Lock()

    def _run(self, query: str, owner_agent: str):
        with self.lock:
            # Verify owner
            if not self.is_authorized_owner(owner_agent):
                return f"Access denied. Agent {owner_agent} not authorized"
            return self.db.query(query)

    def is_authorized_owner(self, agent_id):
        return agent_id == self.current_owner

from pydantic import BaseModel, Field
from typing import Dict, Any

class HandoffSchema(BaseModel):
    task_id: str
    status: str = Field(..., regex='^(pending|working|completed|failed)$')
    context: Dict[str, Any]
    next_agent: str

class CheckpointedAgent:
    def handoff(self, state):
        handoff = HandoffSchema(
            task_id=state['task_id'],
            status='completed',
            context=state,
            next_agent='researcher'
        )
        return {'handoff': handoff.model_dump()}
